const form=document.querySelector("#form");const nome=document.querySelector("#nome");const email=document.querySelector("#email");const senha=document.querySelector("#senha");form.addEventListener("submit",(e)=>{e.preventDefault();const retorno=validarDadosUsuario(nome,email,senha);if(retorno.estadoErro){alternarDialogo(!0,retorno.msgErro);limparCampo(retorno.campoErro);return}
e.currentTarget.submit()})